import json, os

# List available variables
print('Available variables:', list(locals().keys()))

# Try to access the MongoDB results
try:
    papers_var = locals()['var_functions.query_db:28']
    print('Type of papers_var:', type(papers_var))

    # Check if it's a list (direct results) or string (file path)
    if isinstance(papers_var, list):
        papers_2016 = papers_var
        print('papers_var is a list, length:', len(papers_2016))
    elif isinstance(papers_var, str) and os.path.exists(papers_var):
        with open(papers_var, 'r') as f:
            papers_2016 = json.load(f)
        print('Loaded papers from file, length:', len(papers_2016))
    else:
        print('papers_var type not recognized')
        papers_2016 = []

    if papers_2016 and len(papers_2016) > 0:
        print('First paper:', type(papers_2016[0]))
        if isinstance(papers_2016[0], dict):
            print('Paper keys:', papers_2016[0].keys())
except Exception as e:
    print('Error accessing papers:', e)
    papers_2016 = []

# Try to access the citations results  
try:
    citations_var = locals()['var_functions.query_db:30']
    print('\nType of citations_var:', type(citations_var))

    if isinstance(citations_var, list):
        pa_citations = citations_var
        print('citations_var is a list, length:', len(pa_citations))
    elif isinstance(citations_var, str) and os.path.exists(citations_var):
        with open(citations_var, 'r') as f:
            pa_citations = json.load(f)
        print('Loaded citations from file, length:', len(pa_citations))
    else:
        print('citations_var type not recognized')
        pa_citations = []

    if pa_citations and len(pa_citations) > 0:
        print('First citation:', type(pa_citations[0]))
        if isinstance(pa_citations[0], dict):
            print('Citation keys:', pa_citations[0].keys())
except Exception as e:
    print('Error accessing citations:', e)
    pa_citations = []

